const body = $input.first().json.body ?? $input.first().json;
const { userId, userProfile, candidates } = body;

const candidatesList = (candidates ?? []).map((p, i) =>
  `${i + 1}. ID:${p.id} | ${p.name} | ${p.district} | от ${((p.priceFrom ?? 0) / 1_000_000).toFixed(1)} млн | ${p.areaMin ?? '?'}–${p.areaMax ?? '?'} м² | ${p.status === 'ready' ? 'сдан' : 'строится'}${p.isHot ? ' [ХИТ]' : ''}`
).join('\n');

const profileStr = [
  userProfile?.budgetMin ? `бюджет от ${(userProfile.budgetMin / 1_000_000).toFixed(1)} млн` : '',
  userProfile?.budgetMax ? `до ${(userProfile.budgetMax / 1_000_000).toFixed(1)} млн` : '',
  userProfile?.intent    ? `намерение: ${userProfile.intent}` : '',
  userProfile?.userPreferences?.rooms     ? `комнат: ${userProfile.userPreferences.rooms.join(',')}` : '',
  userProfile?.userPreferences?.districts ? `районы: ${userProfile.userPreferences.districts.join(',')}` : '',
].filter(Boolean).join(', ');

const systemPrompt = `Ты — AI-подбор недвижимости. Выбери 5 лучших ЖК для пользователя и дай краткое обоснование для каждого.\n\nПрофиль: ${profileStr || 'не заполнен'}.\n\nДоступные ЖК:\n${candidatesList}\n\nОтветь строго в формате JSON (без markdown):\n{\n  "summary": "краткий текст о подборке (1-2 предложения)",\n  "properties": [\n    { "id": число, "reason": "почему подходит (до 60 символов)" }\n  ]\n}`;

return [{ json: { systemPrompt, candidates: candidates ?? [], userId } }];

const raw        = $input.first().json.choices?.[0]?.message?.content ?? '{}';
const candidates = $('Build GPT Prompt').first().json.candidates ?? [];

let parsed;
try {
  parsed = JSON.parse(raw);
} catch {
  return [{ json: { properties: [], summary: '', source: 'ai' } }];
}

const enriched = (parsed.properties ?? []).map((rec) => {
  const original = candidates.find((c) => c.id === rec.id);
  if (!original) return null;
  return {
    id:        original.id,
    name:      original.name,
    slug:      original.slug,
    district:  original.district,
    priceFrom: original.priceFrom,
    priceM2:   original.priceM2,
    status:    original.status,
    reason:    rec.reason,
  };
}).filter(Boolean);

return [{ json: { properties: enriched, summary: parsed.summary ?? '', source: 'ai' } }];
